class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        int n = s.size();
        int num = stoi(s, 0, 2);
        vector<vector<int>> memo(n + 1, vector<int>(32, -1));
        auto countSetBits = [&](int x) {
            int count = 0;
            while (x) {
                count += x & 1;
                x >>= 1;
            }
            return count;
        };

        function<int(int, int)> dfs = [&](int i, int x) {
            if (x == 0) return 0;
            if (i == n) return 1;
            if (memo[i][x] != -1) return memo[i][x];
            int res = 0;
            if (s[i] == '1') {
                res += dfs(i + 1, x - 1);
                res %= (int)(1e9 + 7);
                res += dfs(i + 1, countSetBits(x));
            } else {
                res += dfs(i + 1, x);
            }
            res %= (int)(1e9 + 7);
            return memo[i][x] = res;
        };

        int count = 0;
        for (int i = 1; i <= 31; ++i) {
            int steps = 0;
            int x = i;
            while (x != 1 && steps <= k) {
                x = countSetBits(x);
                steps++;
            }
            if (steps <= k) count++;
        }
        return (dfs(0, count) - (num <= count)) % (int)(1e9 + 7);
    }
};
